(836, 'Rust Programming: Systems & Web', 'rust-programming-systems-web', 'Master Rust for systems programming, WebAssembly, and high-performance backend applications.', 2, @mentor_id, 4316, 'all-levels', 'Online, Classroom, Hybrid, Corporate', 'Completion Certificate', 'Weekday / Weekend / Flexible', 'Pune, Mumbai, Nagpur, Hyderabad, Delhi, Bangalore, Chennai, + 20 more cities', 'https://via.placeholder.com/400x250?text=Rust%20Programming%3A%20Systems%20%26%20Web', 4.6, 296, 1),
(837, 'Swift Development for iOS & macOS', 'swift-development-for-ios-macos', 'Learn Swift programming for building iOS, macOS, and cross-platform Apple platform applications.', 2, @mentor_id, 3320, 'all-levels', 'Online, Classroom, Hybrid, Corporate', 'Globally Recognized Certificate', 'Weekday / Weekend / Flexible', 'Pune, Mumbai, Nagpur, Hyderabad, Delhi, Bangalore, Chennai, + 20 more cities', 'https://via.placeholder.com/400x250?text=Swift%20Development%20for%20iOS%20%26%20macOS', 4.7, 297, 1);
INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1, 1, 'Basic Level Syllabus', 'Duration: 6 hours | Level: basic | Topics: Introduction to UI/UX Design Principles | Design Thinking Process | Color Theory & Typography | User Research Methods (Interviews, Surveys) | Wireframing with Figma | Prototyping Basics | Usability Testing | Information Architecture & User Flows | Responsive Design Principles | Accessibility (WCAG Guidelines) | Introduction to Design Systems | Mini Project: Mobile App Wireframe', 1),
(2, 1, 'Intermediate Level Syllabus', 'Duration: 12 hours | Level: intermediate | Topics: Advanced Figma: Components, Auto Layout & Variants | User Journey Mapping & Personas | Interaction Design & Micro-animations | Advanced Prototyping & Motion Design | A/B Testing for UX | Design Critique & Iteration | Handoff to Developers (Zeplin/Figma Dev Mode) | Visual Hierarchy & Gestalt Principles | App Design Patterns (iOS & Android) | Portfolio Building | Client Communication & Presentation | Intermediate Project: End-to-End App Design', 2),
(3, 1, 'Advanced Level Syllabus', 'Duration: 22 hours | Level: advanced | Topics: Design System Architecture & Governance | Service Design & Experience Strategy | Advanced User Research (Eye Tracking, Usability Labs) | Quantitative UX Research | UX Strategy & Business Alignment | Inclusive Design | Motion Design with After Effects | Design Leadership & Team Management | UX Writing & Content Design | Measuring UX: Metrics & Analytics | Cross-Platform Design (Web, Mobile, Watch) | Capstone: Enterprise Design System', 3);
