(776, 259, 'Intermediate Level Syllabus', 'Duration: 22 hours | Level: intermediate | Topics: Advanced IAM & Organizations | Amazon ECS & EKS (Container Services) | AWS Lambda & Serverless Architecture | Amazon API Gateway | Amazon CloudFront (CDN) | AWS CloudFormation (Infrastructure as Code) | Amazon SQS, SNS & EventBridge | AWS CodePipeline & CodeDeploy (CI/CD) | Amazon CloudWatch: Monitoring & Logging | AWS Security Services (GuardDuty, Shield, WAF) | Data Analytics: Athena, Glue, EMR | Intermediate Project: Serverless Web Application', 2),
(777, 259, 'Advanced Level Syllabus', 'Duration: 38 hours | Level: advanced | Topics: AWS Solutions Architecture: Well-Architected Framework | Microservices with EKS & Service Mesh | AWS Data Lake Architecture | Machine Learning with SageMaker | Advanced Networking: Transit Gateway, Direct Connect | Multi-Account Strategies & Control Tower | AWS Cost Optimization Strategies | Disaster Recovery & Business Continuity | Advanced Security & Compliance (SOC2, PCI DSS) | Hybrid Cloud with AWS Outposts | AWS Certification Preparation (SAA-C03/SAP-C02) | Capstone: Production-Grade Cloud Architecture', 3);
INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(778, 260, 'Basic Level Syllabus', 'Duration: 12 hours | Level: basic | Topics: Introduction to DevOps Culture & Principles | Version Control with Git & GitHub | Linux Fundamentals for DevOps | Introduction to CI/CD Concepts | Continuous Integration with Jenkins | Docker: Containerization Basics | Building & Running Docker Containers | Docker Compose | Introduction to Cloud (AWS/Azure/GCP) | Infrastructure Basics: Servers, Networking | Bash Scripting Fundamentals | Mini Project: Automate Build & Test with Jenkins', 1),
(779, 260, 'Intermediate Level Syllabus', 'Duration: 22 hours | Level: intermediate | Topics: Kubernetes: Pods, Deployments, Services & Ingress | Helm Charts & Package Management | Terraform for Infrastructure as Code | Ansible for Configuration Management | Advanced CI/CD with GitHub Actions / GitLab CI | Container Registry (ECR, ACR, GCR) | Monitoring with Prometheus & Grafana | Log Management with ELK Stack | AWS/Azure DevOps Services | Security in DevOps (DevSecOps) | Blue-Green & Canary Deployments | Intermediate Project: Kubernetes Deployment Pipeline', 2),
(780, 260, 'Advanced Level Syllabus', 'Duration: 38 hours | Level: advanced | Topics: GitOps with ArgoCD & Flux | Service Mesh with Istio | Advanced Kubernetes: Operators, CRDs, RBAC | Multi-Cloud & Hybrid Cloud Strategies | Advanced Terraform: Modules, Remote State, Workspaces | Chaos Engineering with Chaos Monkey | SRE Principles: SLIs, SLOs, SLAs, Error Budgets | Advanced Observability: Distributed Tracing (Jaeger) | FinOps & Cloud Cost Optimization | Platform Engineering & Internal Developer Portals | Compliance & Security Automation | Capstone: Production-Grade Cloud-Native Platform', 3);
