INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1363, 455, 'Basic Level Syllabus', 'Duration: 12 hours | Level: basic | Topics: Introduction to Project Management & PMBOK | Project Lifecycle Phases | Stakeholder Identification & Communication | Scope Management: WBS & Requirements | Schedule Management: Gantt Charts & Critical Path | Budget Estimation & Cost Management | Risk Identification & Basic Mitigation | Team Leadership Fundamentals | Project Kickoff & Charter | Status Reporting & Documentation | Introduction to Agile vs Waterfall | Mini Project: Plan a Small IT Project', 1),
(1364, 455, 'Intermediate Level Syllabus', 'Duration: 22 hours | Level: intermediate | Topics: Advanced Scope & Change Management | Earned Value Management (EVM) | Resource Planning & Conflict Resolution | Procurement Management | Quality Management (PDCA, Six Sigma basics) | Communication Planning & Stakeholder Engagement | Risk Response Strategies & Risk Register | Project Scheduling with MS Project | Agile Project Management (Scrum, Kanban) | Lessons Learned & Project Closure | PMI Ethics & Professional Responsibility | Intermediate Project: Full Project Plan with Risk Register', 2),
(1365, 455, 'Advanced Level Syllabus', 'Duration: 36 hours | Level: advanced | Topics: PMP Exam Preparation (All 5 Process Groups & 10 Knowledge Areas) | Program & Portfolio Management | Benefits Realization Management | Agile at Scale (SAFe, LeSS) | Organizational Change Management | Advanced Risk & Issues Management | Project Governance & Audit | Strategic Alignment of Projects | Virtual & Global Team Management | Crisis Management in Projects | Measuring Project Success & OKRs | Capstone: Mock PMP Exam + Full Project Case Study', 3);
