INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1525, 509, 'Basic Level Syllabus', 'Duration: 10 hours | Level: basic | Topics: Introduction to Databases & RDBMS | SQL Syntax & Environment Setup | SELECT, WHERE, ORDER BY, LIMIT | INSERT, UPDATE, DELETE | Data Types in SQL | Filtering with AND/OR/NOT | Aggregate Functions: COUNT, SUM, AVG, MIN, MAX | GROUP BY & HAVING | Basic JOINs: INNER, LEFT, RIGHT | Introduction to Indexes | Creating & Dropping Tables | Mini Project: Querying a Sales Database', 1),
(1526, 509, 'Intermediate Level Syllabus', 'Duration: 18 hours | Level: intermediate | Topics: Advanced JOINs & Self Joins | Subqueries & Correlated Subqueries | Common Table Expressions (CTEs) | Window Functions: ROW_NUMBER, RANK, LAG, LEAD | Views & Materialized Views | Stored Procedures & Functions | Triggers & Events | Transactions & ACID Properties | Query Optimization & Execution Plans | Normalization (1NF, 2NF, 3NF, BCNF) | Working with JSON/XML in SQL | Intermediate Project: HR Database System', 2),
(1527, 509, 'Advanced Level Syllabus', 'Duration: 32 hours | Level: advanced | Topics: Advanced Performance Tuning & Indexing Strategies | Partitioning & Sharding | Replication & High Availability | Data Warehousing Concepts (Star/Snowflake Schema) | Dimensional Modeling | ETL using SQL | OLAP & Analytical Queries | Advanced Security: Roles, Grants, Row-Level Security | Cloud SQL (AWS RDS, Azure SQL, BigQuery) | NoSQL vs SQL Tradeoffs | Auditing & Compliance | Capstone: Data Warehouse Design & Implementation', 3);
