INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1792, 598, 'Basic Level Syllabus', 'Duration: 10 hours | Level: basic | Topics: Introduction to Microsoft Azure & Cloud Concepts | Azure Portal & Azure CLI | Azure Active Directory (Entra ID) & Identity Management | Azure Virtual Machines & Compute Services | Azure Blob Storage & Azure Files | Azure Networking: VNet, Subnets, NSG | Azure SQL Database & Cosmos DB Basics | Azure App Service & Azure Functions | Azure Monitor & Log Analytics | Azure Pricing Calculator & Cost Management | Azure Subscriptions & Resource Groups | Mini Project: Deploy a Web App on Azure App Service', 1),
(1793, 598, 'Intermediate Level Syllabus', 'Duration: 20 hours | Level: intermediate | Topics: Azure Kubernetes Service (AKS) | Azure DevOps: Pipelines, Repos & Boards | Azure Logic Apps & API Management | Azure Service Bus & Event Grid | Azure ARM Templates & Bicep (IaC) | Azure Container Instances & Registry | Advanced Azure Networking (VPN Gateway, ExpressRoute) | Azure Key Vault & Security Center | Azure Data Factory & Synapse Analytics | Azure Cognitive Services & AI | Azure AD B2C & Conditional Access | Intermediate Project: Containerized Microservices on AKS', 2),
(1794, 598, 'Advanced Level Syllabus', 'Duration: 32 hours | Level: advanced | Topics: Azure Well-Architected Framework | Multi-Region High Availability Architectures | Azure Governance: Policies, Blueprints & Management Groups | Advanced Security: Sentinel (SIEM), Defender for Cloud | Azure Landing Zone Design | Infrastructure as Code with Terraform on Azure | Azure Machine Learning Service | Real-Time Analytics with Azure Stream Analytics | Azure Digital Twins & IoT Hub | FinOps on Azure | Azure Certification Prep (AZ-104/AZ-305) | Capstone: Enterprise Azure Architecture', 3);
INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1795, 599, 'Basic Level Syllabus', 'Duration: 10 hours | Level: basic | Topics: Introduction to Cybersecurity & Threat Landscape | CIA Triad (Confidentiality, Integrity, Availability) | Networking Fundamentals (TCP/IP, DNS, HTTP/S) | Operating System Security (Windows & Linux) | Introduction to Cryptography | Password Security & Multi-Factor Authentication | Malware Types & Antivirus Basics | Phishing & Social Engineering | Introduction to Firewalls & IDS/IPS | Security Policies & Compliance Basics | Introduction to OWASP Top 10 | Mini Project: Network Vulnerability Scan', 1),
(1796, 599, 'Intermediate Level Syllabus', 'Duration: 20 hours | Level: intermediate | Topics: Network Security: VPN, NAT, DMZ | Web Application Security (XSS, SQL Injection, CSRF) | Penetration Testing Methodology | Kali Linux & Security Tools (Nmap, Metasploit, Wireshark) | Identity & Access Management (IAM) | Security Information & Event Management (SIEM) | Incident Response Process | Digital Forensics Basics | Cloud Security (AWS Security, Azure Defender) | GDPR, HIPAA & Compliance Frameworks | Vulnerability Management | Intermediate Project: Web App Penetration Test', 2),
(1797, 599, 'Advanced Level Syllabus', 'Duration: 32 hours | Level: advanced | Topics: Advanced Penetration Testing (Red Teaming) | Exploit Development & Reverse Engineering | Advanced Malware Analysis | Threat Intelligence & Hunting | SOC Operations & Playbooks | Zero Trust Architecture | Advanced Cloud Security & CASB | Identity Federation (SAML, OAuth, OpenID Connect) | Secure DevOps (DevSecOps Pipeline) | Advanced Forensics & Incident Response | Security Architecture & Risk Management | Capstone: Full Security Assessment & Remediation Report', 3);
INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1798, 600, 'Basic Level Syllabus', 'Duration: 10 hours | Level: basic | Topics: Introduction to Data Analytics | Data Types & Sources | Excel for Data Analysis | Introduction to SQL | Basic Statistics: Mean, Median, Mode, Standard Deviation | Data Cleaning & Preparation | Data Visualization Basics (Charts & Graphs) | Introduction to Business Intelligence | Google Analytics Fundamentals | KPI Definition & Tracking | Reporting & Storytelling with Data | Mini Project: Sales Data Analysis in Excel', 1),
(1799, 600, 'Intermediate Level Syllabus', 'Duration: 20 hours | Level: intermediate | Topics: Advanced SQL for Analytics | Python/R for Data Analysis | Statistical Inference & Hypothesis Testing | A/B Testing & Experimentation | Advanced Visualization with Tableau/Power BI | Customer Analytics & Segmentation | Web Analytics & Funnel Analysis | Cohort Analysis & Retention Metrics | Predictive Analytics Basics | Dashboarding & Executive Reporting | Data Governance & Quality | Intermediate Project: Marketing Campaign Analytics', 2),
(1800, 600, 'Advanced Level Syllabus', 'Duration: 32 hours | Level: advanced | Topics: Advanced Statistical Modeling | Machine Learning for Analytics | Real-Time Analytics with Streaming Data | Big Data Analytics with Spark | Cloud Analytics Platforms (BigQuery, Redshift) | Advanced Attribution Modeling | Forecasting & Demand Planning | Text & Sentiment Analytics | Graph Analytics | Analytics Engineering with dbt | Data Product Management | Capstone: Enterprise Analytics Platform', 3);
INSERT INTO `course_modules` (id, course_id, title, description, sequence) VALUES
(1801, 601, 'Basic Level Syllabus', 'Duration: 8 hours | Level: basic | Topics: Introduction to Databases & RDBMS | SQL Syntax & Environment Setup | SELECT, WHERE, ORDER BY, LIMIT | INSERT, UPDATE, DELETE | Data Types in SQL | Filtering with AND/OR/NOT | Aggregate Functions: COUNT, SUM, AVG, MIN, MAX | GROUP BY & HAVING | Basic JOINs: INNER, LEFT, RIGHT | Introduction to Indexes | Creating & Dropping Tables | Mini Project: Querying a Sales Database', 1),
(1802, 601, 'Intermediate Level Syllabus', 'Duration: 16 hours | Level: intermediate | Topics: Advanced JOINs & Self Joins | Subqueries & Correlated Subqueries | Common Table Expressions (CTEs) | Window Functions: ROW_NUMBER, RANK, LAG, LEAD | Views & Materialized Views | Stored Procedures & Functions | Triggers & Events | Transactions & ACID Properties | Query Optimization & Execution Plans | Normalization (1NF, 2NF, 3NF, BCNF) | Working with JSON/XML in SQL | Intermediate Project: HR Database System', 2),
(1803, 601, 'Advanced Level Syllabus', 'Duration: 28 hours | Level: advanced | Topics: Advanced Performance Tuning & Indexing Strategies | Partitioning & Sharding | Replication & High Availability | Data Warehousing Concepts (Star/Snowflake Schema) | Dimensional Modeling | ETL using SQL | OLAP & Analytical Queries | Advanced Security: Roles, Grants, Row-Level Security | Cloud SQL (AWS RDS, Azure SQL, BigQuery) | NoSQL vs SQL Tradeoffs | Auditing & Compliance | Capstone: Data Warehouse Design & Implementation', 3);
